    @php
        $multiChairSplit = $avail['status'] === 'multi_chair' ? $avail['schedule'] : [];
        $assignedChair = $avail['status'] === 'single_chair' ? $avail['chair_id'] : null;

        $allChairs = \App\Models\Chair::pluck('name', 'id')->toArray();
        $chairData = [
            1 => ['x' => 38, 'y' => 339, 'href' => '#image'],
            2 => ['x' => 38, 'y' => 525, 'href' => '#image'],
            3 => ['x' => 38, 'y' => 711, 'href' => '#image'],
            4 => ['x' => 311, 'y' => 526, 'href' => '#image-2'],
            5 => ['x' => 311, 'y' => 693, 'href' => '#image-2'],
            6 => ['x' => 460, 'y' => 525, 'href' => '#image'],
            7 => ['x' => 460, 'y' => 693, 'href' => '#image']
        ];
    @endphp

    @foreach($chairData as $cid => $data)
        @php
            $isMultiAssigned = in_array($cid, $multiChairSplit);
            $isSelected = ($avail['status'] === 'single_chair' && $cid == $assignedChair) || ($avail['status'] === 'multi_chair' && $isMultiAssigned);
            $chairName = $allChairs[$cid] ?? 'Chair ' . $cid;
        @endphp
        
        <use id="chair-{{ $cid }}" x="{{ $data['x'] }}" y="{{ $data['y'] }}" xlink:href="{{ $data['href'] }}" @if($isSelected) filter="url(#chair-green)" @endif/>
        <text x="{{ $data['x'] > 400 ? $data['x'] + 160 : $data['x'] - 10 }}" y="{{ $data['y'] + 80 }}" font-size="22" font-family="Arial, sans-serif" fill="#333333" font-weight="bold" text-anchor="{{ $data['x'] > 400 ? 'start' : 'end' }}" style="pointer-events:none;">{{ $loop->iteration }}</text>
    @endforeach

    @foreach($chairData as $cid => $data)
        @php
            $isMultiAssigned = in_array($cid, $multiChairSplit);
            $isSelected = ($avail['status'] === 'single_chair' && $cid == $assignedChair) || ($avail['status'] === 'multi_chair' && $isMultiAssigned);
            $chairName = $allChairs[$cid] ?? 'Chair ' . $cid;
        @endphp
        
        @if($isSelected)
            @php
                if($avail['status'] === 'multi_chair') {
                    $hourIndex = array_search($cid, $multiChairSplit);
                    $startHour = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->addHours($hourIndex)->format('g:i A');
                    $endHour = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->addHours($hourIndex + 1)->format('g:i A');
                    $hourLabel = ($hourIndex == 0) ? '1st Hour' : (($hourIndex == 1) ? '2nd Hour' : 'Hour '.($hourIndex+1));
                } else {
                    $startHour = \Carbon\Carbon::parse(session('stylist_booking.start_time'))->format('g:i A');
                    $endHour = \Carbon\Carbon::parse(session('stylist_booking.end_time'))->format('g:i A');
                    $hourLabel = 'Full Duration';
                }
            @endphp
            <rect x="{{ $data['x'] - 20 }}" y="{{ $data['y'] - 60 }}" width="230" height="45" fill="#fff" rx="6" filter="drop-shadow(0px 4px 10px rgba(0,0,0,0.15))"/>
            <text x="{{ $data['x'] - 10 }}" y="{{ $data['y'] - 42 }}" font-size="12" fill="#111" font-weight="bold">{{ $chairName }}: {{ $startHour }} - {{ $endHour }}</text>
            <text x="{{ $data['x'] - 10 }}" y="{{ $data['y'] - 26 }}" font-size="11" fill="#666">({{ $hourLabel }})</text>
        @endif
    @endforeach
    @if($avail['status'] === 'multi_chair' && count($multiChairSplit) > 1)
        <!-- Arrow Defs -->
        <defs>
            <marker id="arrowhead" markerWidth="10" markerHeight="7" refX="9" refY="3.5" orient="auto">
                <polygon points="0 0, 10 3.5, 0 7" fill="#17b081" />
            </marker>
        </defs>
        
        @for($i = 0; $i < count($multiChairSplit) - 1; $i++)
            @php
                $fromCid = $multiChairSplit[$i];
                $toCid = $multiChairSplit[$i+1];
                if (isset($chairData[$fromCid]) && isset($chairData[$toCid])) {
                    $fromData = $chairData[$fromCid];
                    $toData = $chairData[$toCid];
                    
                    // Chair center is roughly x + 75, y + 73
                    $fromX = $fromData['x'] + 75;
                    $fromY = $fromData['y'] + 73;
                    $toX = $toData['x'] + 75;
                    $toY = $toData['y'] + 73;
                    
                    // We want to stop the arrow a bit before the exact center so it's visible outside the chair icon if possible, 
                    // or just draw it on top. Let's draw it on top but make it noticeable.
                }
            @endphp
            @if(isset($fromX))
                <!-- A nice thick dashed arrow -->
                <line x1="{{ $fromX }}" y1="{{ $fromY }}" x2="{{ $toX }}" y2="{{ $toY }}" stroke="#17b081" stroke-width="5" stroke-dasharray="10,6" marker-end="url(#arrowhead)" style="filter: drop-shadow(0px 2px 4px rgba(0,0,0,0.3));" />
            @endif
        @endfor
    @endif
